    id: "far-d7-002",
    courseId: "cpa",
    section: "FAR",
    blueprintArea: "FAR-III",
    topic: "Business Combinations",
    subtopic: "Measurement of Consideration",
    difficulty: "medium",
    skillLevel: "Application",
    question: "In a business combination, an acquirer pays $5,000,000 cash, issues stock with a fair value of $3,000,000, and agrees to contingent consideration with a fair value of $500,000 at the acquisition date. Direct acquisition costs are $200,000. What is the total acquisition-date consideration?",
    options: ["$8,700,000","$8,500,000 (cash + stock + contingent consideration; acquisition costs are expensed)","$8,200,000","$5,500,000"],
